import java.util.Arrays;

public class Main {
    public static void main(String[] args) {
        int[][] intervals = {{3, 5}, {1, 3}, {2, 7}, {1, 2}};

        Arrays.sort(intervals, (a, b) -> a[0] != b[0] ? a[0] - b[0] : a[1] - b[1]);

        for (int[] iv : intervals) {
            System.out.println(Arrays.toString(iv));
        }
    }
}

